import{_ as e,o as n,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Segment (Import) Configuration","description":"","frontmatter":{"title":"Segment (Import) Configuration","slug":"segment-import-configuration"},"headers":[],"relativePath":"developer-hub/segment-import-configuration.md","filePath":"developer-hub/segment-import-configuration.md"}'),o={name:"developer-hub/segment-import-configuration.md"};function s(d,t,i,c,l,p){return n(),a("div",null,[...t[0]||(t[0]=[r(`<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sending events from Segment to Branch will allow you to attribute downstream conversions like purchases across web and app to Branch link clicks. Events imported from Segment to Branch will be available wherever you can normally use events within Branch, including dashboard visualizations, Data Feeds, Ads Postbacks, Journeys targeting, Liveview and more.</p><p>This guide walks through the server-side integration for data import from Segment to Branch. For data export from Branch to Segment, go <a href="./segment-export.html">here</a>.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Once the Branch SDK is integrated into an app, Branch can detect which Branch Links are leading to installs, re-opens, and users&#39; actions. Enabling this integration and sending your events to Branch will allow Branch to enhance your Segment data with Branch data.</p><h3 id="branch-events-imported-from-segment" tabindex="-1">Branch Events Imported from Segment <a class="header-anchor" href="#branch-events-imported-from-segment" aria-label="Permalink to &quot;Branch Events Imported from Segment&quot;">​</a></h3><p>Branch will import events that are not auto-tracked with the Branch SDKs. This includes commerce, content, user lifecycle, and custom events, and excludes events like clicks and installs. See the full list of supported events and associated mappings <a href="./segment-import.html#section-supported-events">here</a>. Branch will only import events that can be <a href="./segment-import.html#section-identifiers-for-app-events">tied to a user</a>.</p><div class="warning custom-block"><p class="custom-block-title">Avoid Duplicate Data</p><p>To avoid duplicate data, you should either <a href="./track-branch-events.html">track conversion events directly with Branch</a> or track events with Segment and then enable import to Branch, not both. Branch will warn you if you try to import events to Branch that you are already tracking.</p></div><p>Branch will only import events from Segment that are not already auto-tracked with the Branch SDK. This means that events like click and install cannot be imported. The following outlines how Segment events are mapped to Branch events, and which will be imported to Branch:</p><table tabindex="0"><thead><tr><th>Segment Event</th><th>Branch Event</th><th>Branch Event Category</th><th>Imported</th></tr></thead><tbody><tr><td>Product Added</td><td>Add To Cart</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td>Product Added to Wishlist</td><td>Add To Wishlist</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td>Cart Viewed</td><td>View Cart</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td>Payment Info Entered</td><td>Add Payment Info</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td>Checkout Started</td><td>Initiate Purchase</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td>Order Completed</td><td>Purchase</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>Spend Credits</td><td>Commerce Event</td><td><strong>Yes</strong></td></tr><tr><td>Products Searched</td><td>Search</td><td>Content Event</td><td><strong>Yes</strong></td></tr><tr><td>Product Viewed</td><td>View Item</td><td>Content Event</td><td><strong>Yes</strong></td></tr><tr><td>Product List Viewed</td><td>View Items</td><td>Content Event</td><td><strong>Yes</strong></td></tr><tr><td>Product Reviewed</td><td>Rate</td><td>Content Event</td><td><strong>Yes</strong></td></tr><tr><td>Product Shared</td><td>Share</td><td>Content Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>Complete Registration</td><td>Lifecycle Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>Complete Tutorial</td><td>Lifecycle Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>Achieve Level</td><td>Lifecycle Event</td><td><strong>Yes</strong></td></tr><tr><td><em>use the Branch event name</em></td><td>Unlock Achievement</td><td>Lifecycle Event</td><td><strong>Yes</strong></td></tr><tr><td><em>any event name</em></td><td>Custom</td><td>Custom Event</td><td><strong>Yes</strong></td></tr><tr><td>Deep Link Clicked</td><td>Click</td><td>-</td><td>Not Supported</td></tr><tr><td>Install Attributed</td><td>Install</td><td>-</td><td>Not Supported</td></tr><tr><td>-</td><td>SMS Sent</td><td>-</td><td>Not Supported</td></tr><tr><td>-</td><td>Pageview</td><td>-</td><td>Not Supported</td></tr><tr><td>-</td><td>Web Session Start</td><td>-</td><td>Not Supported</td></tr><tr><td>-</td><td>Branch CTA View</td><td>-</td><td>Not Supported</td></tr><tr><td>-</td><td>Impression</td><td>-</td><td>Not Supported</td></tr><tr><td>Application Installed</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Application Opened</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Application Updated</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Application Backgrounded</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Application Crashed</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Application Uninstalled</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Push Notification Received</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Push Notification Tapped</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Push Notification Bounced</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Screen</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Page</td><td>-</td><td>-</td><td>Not Recommended</td></tr><tr><td>Identify</td><td>-</td><td>-</td><td>Not Recommended</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Segment (import), you need to have completed the following:</p><ol><li>Admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Have either the Engagement or Performance <a href="./packaging.html">product</a> enabled for your Branch Account.</li><li>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</li><li>Implement the Segment SDK</li><li>Admin access to your Segment account.</li></ol><h2 id="enable-segment-import" tabindex="-1">Enable Segment (import) <a class="header-anchor" href="#enable-segment-import" aria-label="Permalink to &quot;Enable Segment (import)&quot;">​</a></h2><h2 id="_1-setup-branch" tabindex="-1">1. Setup Branch <a class="header-anchor" href="#_1-setup-branch" aria-label="Permalink to &quot;1. Setup Branch&quot;">​</a></h2><p><a href="./submit-a-ticket.html">Contact Branch</a> to configure Branch to receive events from Segment. Please note that a subscription to <a href="https://branch.io/data-feeds/" target="_blank" rel="noreferrer">Data Feeds</a> is required to enable data import from Segment to Branch.</p><p>Then, navigate to the <a href="https://branch.dashboard.branch.io/data-feeds/integrations" target="_blank" rel="noreferrer">Data Integrations page</a> of the Branch dashboard.</p><ol><li>Select <strong>Segment</strong> from the menu on the left.</li><li>Select the platforms you would like to import events from and click <strong>Enable</strong>.</li></ol><h2 id="_2-setup-segment" tabindex="-1">2. Setup Segment <a class="header-anchor" href="#_2-setup-segment" aria-label="Permalink to &quot;2. Setup Segment&quot;">​</a></h2><p>Navigate to your Segment UI’s Destinations page.</p><ol><li>Click on <strong>Add Destination</strong>.</li><li>Search for Branch within the Destinations Catalog and confirm the Source you’d like to connect to.</li><li>Enter your Branch Key. This can be found in the <a href="https://dashboard.branch.io/account-settings/app" target="_blank" rel="noreferrer">Account Settings &gt; App</a> section of the Branch dashboard.</li><li>Enter your Branch Secret. This can be found in the <a href="https://dashboard.branch.io/account-settings/app" target="_blank" rel="noreferrer">Account Settings &gt; App</a> section of the Branch dashboard.</li></ol><p>For server-side event import, <strong>you can ignore the SDK integration instructions</strong>.</p><h3 id="segment-identifiers" tabindex="-1">Segment Identifiers <a class="header-anchor" href="#segment-identifiers" aria-label="Permalink to &quot;Segment Identifiers&quot;">​</a></h3><h4 id="identifiers-for-app-events" tabindex="-1">Identifiers for app events <a class="header-anchor" href="#identifiers-for-app-events" aria-label="Permalink to &quot;Identifiers for app events&quot;">​</a></h4><p>Identifiers are required for events to be imported to Branch. You must include:</p><ul><li>context.device.advertisingId <strong>AND</strong> context.os.name <strong>AND</strong> context.os.version</li></ul><p>OR</p><ul><li>context.device.id <strong>AND</strong> context.os.name AND context.os.version</li></ul><p>Branch maps Segment&#39;s identifiers to the following:</p><table tabindex="0"><thead><tr><th>Segment field</th><th>Branch field</th></tr></thead><tbody><tr><td><code>userId</code></td><td><code>developer_identity</code></td></tr><tr><td><code>context.device.advertisingId</code></td><td><code>idfa</code> or <code>aaid</code></td></tr><tr><td><code>context.device.id</code></td><td><code>idfv</code> or <code>android_id</code></td></tr><tr><td><code>context.os.name</code></td><td><code>os</code></td></tr><tr><td><code>context.os.version</code></td><td><code>os_version</code></td></tr></tbody></table><p>If using User ID with Segment, Branch will automatically map this to developer identity. See Developer Identity Instructions for ( <a href="./ios-basic-integration.html#track-users">iOS</a> | <a href="./android-full-reference.html#persistent-identities">Android</a> )</p><p>Check out Segment&#39;s <a href="https://segment.com/docs/spec/identify#user-id" target="_blank" rel="noreferrer">User ID docs</a> for more details.</p><p>Branch does not map Segment&#39;s anonymous ID to any field, and <a href="./segment-import.html#attribution-for-logged-out-users-on-web">will not attribute logged out web events</a> received from the server-to-server integration. Anonymous ID <a href="./segment-import.html#attaching-anonymous-id-to-events">can still be attached to events</a>.</p><h4 id="identifiers-for-web-events" tabindex="-1">Identifiers for web events <a class="header-anchor" href="#identifiers-for-web-events" aria-label="Permalink to &quot;Identifiers for web events&quot;">​</a></h4><p>In order to attribute accurately on web it is important to collect the Branch SDK&#39;s browser fingerprint and pass it to the Segment track function. Branch uses this along with the <code>userAgent</code> collected by the Segment SDK to identify the user&#39;s persona, platform, os and other parameters. Collecting the browser fingerprint can be done with the following code snippet:</p><div class="warning custom-block"><p class="custom-block-title">For Logged in web Events Only</p><p>Branch does not attribute logged out web events for Segment, even when passing an Anonymous ID.</p></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const loadBranchAndGetFingerprint = new Promise(function(resolve, reject) {</span></span>
<span class="line"><span>  branch.init(&#39;BRANCH_KEY&#39;, {}, function(err, data) {</span></span>
<span class="line"><span>  branch.getBrowserFingerprintId(function(err, fingerprint) {  // fetch the browser fingerprint from the SDK</span></span>
<span class="line"><span>    if (!!err) {</span></span>
<span class="line"><span>      reject(err);</span></span>
<span class="line"><span>      return;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    resolve({...data, fingerprint});</span></span>
<span class="line"><span>  });</span></span>
<span class="line"><span>  });</span></span>
<span class="line"><span>});</span></span></code></pre></div><p>You can then pass it into the payload of the Segment track event:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>loadBranchAndGetFingerprint.then(function(data) {</span></span>
<span class="line"><span>    const { fingerprint } = data;</span></span>
<span class="line"><span>    // Load the Segment SDK and initialize with key here</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // Segment track request</span></span>
<span class="line"><span>    analytics.track(&#39;Order Completed&#39;, {</span></span>
<span class="line"><span>        browser_fingerprint_id: fingerprint // add the browser fingerprint to the Segment track event</span></span>
<span class="line"><span>        //... Other event details ...</span></span>
<span class="line"><span>    })</span></span>
<span class="line"><span>});</span></span></code></pre></div><h3 id="segment-track" tabindex="-1">Segment Track <a class="header-anchor" href="#segment-track" aria-label="Permalink to &quot;Segment Track&quot;">​</a></h3><p>The Branch integration supports some of the events tracked with Segment’s <a href="https://segment.com/docs/spec/track/" target="_blank" rel="noreferrer">Track</a> method. The track API call is how you record any actions your users perform, along with any properties that describe the action.</p><p>Each action is known as an event. Each event has a name, like Registered, and properties, for example a Registered event might have properties like plan or accountType. Here’s the payload of a typical track call with most common fields removed:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;type&quot;: &quot;track&quot;,</span></span>
<span class="line"><span>  &quot;event&quot;: &quot;Registered&quot;,</span></span>
<span class="line"><span>  &quot;properties&quot;: {</span></span>
<span class="line"><span>    &quot;plan&quot;: &quot;Pro Annual&quot;,</span></span>
<span class="line"><span>    &quot;accountType&quot; : &quot;Facebook&quot;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>And here’s the corresponding Javascript event that would generate the above payload:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>analytics.track(&quot;Registered&quot;, {</span></span>
<span class="line"><span>  plan: &quot;Pro Annual&quot;,</span></span>
<span class="line"><span>  accountType: &quot;Facebook&quot;</span></span>
<span class="line"><span>});</span></span></code></pre></div><p>See Segment&#39;s <a href="https://segment.com/docs/spec/track/" target="_blank" rel="noreferrer">Track documentation</a> for more details and examples.</p><h2 id="_3-verify-the-integration" tabindex="-1">3. Verify the integration <a class="header-anchor" href="#_3-verify-the-integration" aria-label="Permalink to &quot;3. Verify the integration&quot;">​</a></h2><p>Once you have import turned on in both Segment and Branch, events should come through. You will see a green dot on the import card if Branch has seen events:</p><p>Branch imports events from Segment as <a href="./segment-import.html#section-supported-events">commerce, user lifecycle, content, or custom events</a>.</p><h4 id="using-imported-events" tabindex="-1">Using imported events <a class="header-anchor" href="#using-imported-events" aria-label="Permalink to &quot;Using imported events&quot;">​</a></h4><p>Events imported from Segment to Branch will be available wherever you can normally use events within Branch. This includes dashboard visualizations, Data Feeds (including Data Integrations, Query API, Webhooks, and Daily Export API), Ads postbacks, Journeys targeting, Liveview and more.</p><h2 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h2><h3 id="attaching-anonymous-id-to-events" tabindex="-1">Attaching anonymous ID to events <a class="header-anchor" href="#attaching-anonymous-id-to-events" aria-label="Permalink to &quot;Attaching anonymous ID to events&quot;">​</a></h3><p>Events imported from Segment with anonymous ID attached will retain that value on the event, and will be available in the custom_data field if exported back out from Branch. To attach anonymous ID to events auto-tracked by Branch (installs, opens, etc.), follow the instructions <a href="./segment-export.html#section-pass-segment-anonymous-id">here</a>.</p><h3 id="attribution-for-logged-out-users-on-web" tabindex="-1">Attribution for logged out users on web <a class="header-anchor" href="#attribution-for-logged-out-users-on-web" aria-label="Permalink to &quot;Attribution for logged out users on web&quot;">​</a></h3><p>Branch uses a custom, in-house identifier for logged out users on web. If you enable the server to server integration from Segment to Branch, you will not be able to attribute logged out web events from Segment to a campaign run with Branch. For this reason, you may want to track web events directly with the Branch web SDK, while still sending app events server to server from Segment. Branch allows you to then toggle web event import off to prevent duplicate data.</p>`,57)])])}const u=e(o,[["render",s]]);export{m as __pageData,u as default};
